SELECT recipes.recipe_name, categories.category_name
FROM recipes
JOIN categories ON recipes.category_id = categories.category_id;

SELECT AVG(version_count) AS AverageVersionsPerRecipe
FROM (
    SELECT recipe_id, COUNT(version_id) AS version_count
    FROM versions
    GROUP BY recipe_id
);

SELECT recipe_name, total_time
FROM recipes
WHERE is_vegetarian = 1 AND total_time > '00:30:00';

SELECT recipe_name
FROM recipes
ORDER BY recipe_name DESC;

SELECT region, COUNT(cuisine_id) AS total_cuisines
FROM cuisines
GROUP BY region;

SELECT 
    (SELECT COUNT(*) FROM recipes) AS total_recipes,
    (SELECT COUNT(*) FROM users) AS total_users;
